17	export const runScenario = (input: any): { results: unknown[] } => {
18	  const items: { type: string }[] = input.steps[0].items;
19	  const premium =
20	    items.reduce((total, item) => total + itemPremium(item), 0) + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	};
